const { Manifold, CrossSection } = api;

// ---------------------------------------------------------------------------
// Japanese five-story pagoda (Goju-no-to). Reference: Horyu-ji / To-ji pagodas.
// Stone base, five tapering tiers of vermilion columns + white walls, each
// capped by a curved roof with upturned eaves, crowned by a bronze sorin spire.
// Z-up. Front faces +Y. Built bottom-up; everything overlaps >=0.5u to union.
// ---------------------------------------------------------------------------

const SEG = 48;

// Collect parts by material so we can self-color via labeledUnion at the end.
const stoneParts = [];
const woodParts = [];    // vermilion timber columns / brackets / balconies
const wallParts = [];    // white plaster wall panels
const roofParts = [];    // dark tiled curved roofs
const bronzeParts = [];  // sorin finial

// --- Curved roof ----------------------------------------------------------
// A square hip roof that rises to a ridge and flares out at the eaves with an
// upturned lip. Built by stacking shrinking square slabs (concave taper) plus
// a flared eave skirt and corner up-turns.
function makeRoof(halfBase, height, z0, eaveOverhang) {
  const eaveHalf = halfBase + eaveOverhang;
  // Smooth concave pyramid via a single hull of: a wide thin eave ring, a
  // mid-height ring, and a small ridge cap. Hulling gives clean swept planes
  // with no stair-stepping, and a square cross-section throughout.
  const eave  = Manifold.cube([eaveHalf * 2, eaveHalf * 2, 0.9], true).translate([0, 0, z0 + 0.45]);
  const mid   = Manifold.cube([halfBase * 1.15, halfBase * 1.15, 0.1], true).translate([0, 0, z0 + height * 0.5]);
  const ridge = Manifold.cube([3.2, 3.2, 0.1], true).translate([0, 0, z0 + height]);
  let body = eave.add(mid).add(ridge).hull();

  // Up-turned corner eaves: at each corner, hull a small slab sitting on the
  // eave with a sphere lifted up-and-outward, giving a graceful concave sweep
  // that tips skyward — the signature pagoda flourish.
  const wings = [];
  const c = eaveHalf - eaveHalf * 0.16;
  for (const [sx, sy] of [[1, 1], [-1, 1], [-1, -1], [1, -1]]) {
    const foot = Manifold.cube([eaveHalf * 0.42, eaveHalf * 0.42, 0.9], true)
      .translate([sx * c, sy * c, z0 + 0.45]);
    const tip = Manifold.sphere(0.95, SEG)
      .translate([sx * (eaveHalf + height * 0.32), sy * (eaveHalf + height * 0.32), z0 + height * 0.6]);
    wings.push(foot.add(tip).hull());
  }
  body = body.add(Manifold.union(wings));

  // Ridge cap block + the four diagonal ridge tiles meeting at the top.
  const cap = Manifold.cube([2.6, 2.6, 1.4], true).translate([0, 0, z0 + height + 0.3]);
  body = body.add(cap);

  return body;
}

// --- One body tier: white walls + vermilion corner columns + door -----------
function makeTier(halfWall, wallH, z0, withDoor) {
  // White plaster wall block.
  const wall = Manifold.cube([halfWall * 2, halfWall * 2, wallH], true)
    .translate([0, 0, z0 + wallH / 2]);
  // Hollow it slightly behind a front opening (cosmetic recess) only on door tier.
  let walls = wall;
  if (withDoor) {
    const door = Manifold.cube([halfWall * 0.5, 4, wallH * 0.7, ], true)
      .translate([0, halfWall - 1, z0 + wallH * 0.35]);
    walls = walls.subtract(door);
  }
  wallParts.push(walls);

  // Four vermilion corner columns (round posts).
  const colR = Math.max(0.9, halfWall * 0.10);
  const colH = wallH + 1.0;
  const cx = halfWall - colR * 0.6;
  for (const [sx, sy] of [[1, 1], [-1, 1], [-1, -1], [1, -1]]) {
    const col = Manifold.cylinder(colH, colR, colR, SEG)
      .translate([sx * cx, sy * cx, z0 - 0.5]);
    woodParts.push(col);
  }
  // Mid columns on each face for the tall first tier (more authentic rhythm).
  if (halfWall > 9) {
    for (const [sx, sy] of [[0, 1], [0, -1], [1, 0], [-1, 0]]) {
      const col = Manifold.cylinder(colH, colR * 0.8, colR * 0.8, SEG)
        .translate([sx * cx, sy * cx, z0 - 0.5]);
      woodParts.push(col);
    }
  }

  // Horizontal vermilion beam (frieze) capping the wall just under the roof.
  const beam = Manifold.cube([halfWall * 2 + colR, halfWall * 2 + colR, 1.3], true)
    .translate([0, 0, z0 + wallH + 0.2]);
  // shell it so it reads as a frame (subtract inner)
  const beamInner = Manifold.cube([halfWall * 2 - 1.4, halfWall * 2 - 1.4, 2.0], true)
    .translate([0, 0, z0 + wallH + 0.2]);
  woodParts.push(beam.subtract(beamInner));

  // Bracket blocks (tokyo) under the eaves at the corners + mid — small cubes.
  const brH = 1.2;
  const brZ = z0 + wallH + 1.0;
  const bcount = halfWall > 9 ? 3 : 2;
  for (const [sx, sy] of [[1, 1], [-1, 1], [-1, -1], [1, -1]]) {
    for (let i = 0; i < bcount; i++) {
      const off = (i - (bcount - 1) / 2) * (colR * 2.2);
      // along each of the two faces meeting at the corner
      woodParts.push(Manifold.cube([1.5, 1.5, brH], true).translate([sx * cx - sx * 0.0 + off, sy * cx, brZ]));
      woodParts.push(Manifold.cube([1.5, 1.5, brH], true).translate([sx * cx, sy * cx - sy * 0.0 + off, brZ]));
    }
  }
}

// --- Balcony / railing ring around the base of each upper tier --------------
function makeBalcony(half, z) {
  const deckHalf = half + 1.6;
  const deck = Manifold.cube([deckHalf * 2, deckHalf * 2, 0.7], true).translate([0, 0, z + 0.35]);
  woodParts.push(deck);
  // Railing: top rail + little posts.
  const railHalf = deckHalf - 0.2;
  const topRail = Manifold.cube([railHalf * 2, railHalf * 2, 0.5], true).translate([0, 0, z + 2.0]);
  const topRailInner = Manifold.cube([railHalf * 2 - 1.0, railHalf * 2 - 1.0, 1.0], true).translate([0, 0, z + 2.0]);
  woodParts.push(topRail.subtract(topRailInner));
  // Posts around the perimeter.
  const n = Math.max(6, Math.round(railHalf * 1.2));
  for (let side = 0; side < 4; side++) {
    for (let i = 0; i <= n; i++) {
      const t = i / n;
      const p = -railHalf + t * railHalf * 2;
      let x, y;
      if (side === 0) { x = p; y = railHalf; }
      else if (side === 1) { x = p; y = -railHalf; }
      else if (side === 2) { x = railHalf; y = p; }
      else { x = -railHalf; y = p; }
      woodParts.push(Manifold.cube([0.35, 0.35, 1.7], true).translate([x, y, z + 1.2]));
    }
  }
}

// ===========================================================================
// Assemble
// ===========================================================================

// --- Stone base platform (two stacked stepped plinths) ---------------------
let zCursor = 0;
const baseH1 = 3.0, baseH2 = 2.2;
const baseHalf1 = 22, baseHalf2 = 19;
stoneParts.push(Manifold.cube([baseHalf1 * 2, baseHalf1 * 2, baseH1], true).translate([0, 0, baseH1 / 2]));
stoneParts.push(Manifold.cube([baseHalf2 * 2, baseHalf2 * 2, baseH2], true).translate([0, 0, baseH1 + baseH2 / 2]));
// Front entry steps.
for (let i = 0; i < 3; i++) {
  const w = 12 - i * 1.5;
  stoneParts.push(Manifold.cube([w * 2, 3, (i + 1) * 1.0], true)
    .translate([0, baseHalf1 - 0.5 + (3 - i) * 1.4, (i + 1) * 0.5]));
}
zCursor = baseH1 + baseH2;

// Five tiers. Each shrinks; wall height also shrinks gently.
const tierHalfs = [15.5, 13.2, 11.0, 8.9, 7.0];
const wallHs    = [12.0, 10.0, 8.6, 7.4, 6.4];
const roofHs    = [6.5, 5.7, 5.0, 4.4, 4.0];
const eaveOver  = [6.5, 5.8, 5.2, 4.6, 4.2];

for (let tier = 0; tier < 5; tier++) {
  const half = tierHalfs[tier];
  const wallH = wallHs[tier];
  const roofH = roofHs[tier];

  // Balcony deck under tiers 2..5 (the platform the upper body sits on).
  if (tier > 0) {
    makeBalcony(half, zCursor - 0.4);
  }

  // Body of the tier.
  makeTier(half, wallH, zCursor, tier === 0);
  const bodyTop = zCursor + wallH;

  // Roof for this tier. Start it right at the wall top so the eave skirt just
  // overlaps the frieze beam (roof unions to the body, no float) while leaving
  // the white wall + vermilion columns of the tier clearly visible.
  const roof = makeRoof(half + 1.0, roofH, bodyTop + 0.1, eaveOver[tier]);
  roofParts.push(roof);

  // Next tier sits down inside this roof so they overlap (no floating),
  // leaving the body of each tier clearly visible between the deep eaves.
  zCursor = bodyTop + roofH * 0.62;
}

// --- Shinbashira: central structural mast tying every tier together --------
// A historically-accurate central pillar runs the full height of the tower;
// here it also guarantees the stacked tiers union into one connected body.
const coreTop = zCursor + 1.0;
woodParts.push(Manifold.cylinder(coreTop - baseH1, 1.4, 1.0, SEG).translate([0, 0, baseH1]));

// --- Sorin: the bronze finial spire on top ---------------------------------
const finialZ0 = zCursor + 2.0;
// Inverted-bowl base (rokuju).
bronzeParts.push(Manifold.sphere(3.2, SEG)
  .scale([1, 1, 0.55])
  .translate([0, 0, finialZ0]));
// Central mast.
const mastH = 16;
bronzeParts.push(Manifold.cylinder(mastH, 0.7, 0.55, SEG).translate([0, 0, finialZ0]));
// Nine stacked rings (kurin).
for (let i = 0; i < 9; i++) {
  const z = finialZ0 + 2.2 + i * 1.35;
  const r = 2.6 - i * 0.16;
  const ring = Manifold.cylinder(0.45, r, r, SEG).translate([0, 0, z]);
  const hole = Manifold.cylinder(1.2, r - 0.55, r - 0.55, SEG).translate([0, 0, z - 0.4]);
  bronzeParts.push(ring.subtract(hole));
  // mast already fills the center so rings connect to it.
}
// Flaming jewel (hoju) at the very top.
const topZ = finialZ0 + 2.2 + 9 * 1.35 + 1.0;
bronzeParts.push(Manifold.sphere(1.5, SEG).scale([1, 1, 1.4]).translate([0, 0, topZ]));
bronzeParts.push(Manifold.cylinder(2.0, 0.6, 0.0, SEG).translate([0, 0, topZ + 1.6]));

// ---------------------------------------------------------------------------
const stone = Manifold.union(stoneParts);
const wood = Manifold.union(woodParts);
const wall = Manifold.union(wallParts);
const roof = Manifold.union(roofParts);
const bronze = Manifold.union(bronzeParts);

return api.labeledUnion([
  { name: 'stone_base', shape: stone, color: '#9a9186' },     // weathered granite
  { name: 'timber', shape: wood, color: '#b1402c' },          // vermilion lacquered wood
  { name: 'walls', shape: wall, color: '#f3ece0' },           // white plaster
  { name: 'roofs', shape: roof, color: '#3a4a52' },           // dark blue-grey tile
  { name: 'sorin', shape: bronze, color: '#b08d3c' },         // weathered bronze
]);
